using System;
using System.Collections.Generic;
using System.Numerics;
using System.Security.Cryptography;

namespace SakuraEDL.MediaTek.Auth
{
    public class SlaKey
    {
        public string Vendor { get; set; }
        public ushort[] DaCodes { get; set; }
        public string Name { get; set; }
        public string D { get; set; } // hex string
        public string N { get; set; } // hex string
        public string E { get; set; } // hex string

        private BigInteger? _dInt, _nInt, _eInt;

        public SlaKey(string vendor, ushort[] daCodes, string name, string d, string n, string e)
        {
            Vendor = vendor;
            DaCodes = daCodes ?? new ushort[0];
            Name = name;
            D = d;
            N = n;
            E = e;
        }

        public BigInteger GetD()
        {
            if (!_dInt.HasValue) _dInt = Sla.HexToBigInteger(D);
            return _dInt.Value;
        }

        public BigInteger GetN()
        {
            if (!_nInt.HasValue) _nInt = Sla.HexToBigInteger(N);
            return _nInt.Value;
        }

        public BigInteger GetE()
        {
            if (!_eInt.HasValue) _eInt = Sla.HexToBigInteger(E);
            return _eInt.Value;
        }

        public RSAParameters ToRsaParameters()
        {
            return new RSAParameters
            {
                Modulus = Sla.BigIntegerToBytes(GetN(), 256),
                Exponent = Sla.BigIntegerToBytes(GetE(), 0),
                D = Sla.BigIntegerToBytes(GetD(), 256)
            };
        }
    }

