        /// <summary>
        /// Find matching SLA key by DA code.
        /// </summary>
        public static SlaKey FindByDaCode(ushort daCode)
        {
            foreach (var key in DaSlaKeys)
            {
                if (key.DaCodes != null)
                {
                    foreach (var code in key.DaCodes)
                    {
                        if (code == daCode)
                            return key;
                    }
                }
            }
            return null;
        }

        /// <summary>
        /// Find matching SLA key by vendor name.
        /// </summary>
        public static SlaKey FindByVendor(string vendor)
        {
            foreach (var key in DaSlaKeys)
            {
                if (string.Equals(key.Vendor, vendor, StringComparison.OrdinalIgnoreCase))
                    return key;
            }
            return null;
        }

        /// <summary>
        /// Get the default Generic key (index 4 — most commonly used).
        /// </summary>
        public static SlaKey GetDefaultKey()
        {
            return DaSlaKeys.Count > 4 ? DaSlaKeys[4] : DaSlaKeys[0];
        }
    }
